+@import "tailwindcss";
+
+/* ==========================================================================
+   FrankenTUI - Global Styles
+   Green / Lime / Emerald Frankenstein theme
+   ========================================================================== */
+
+/* --------------------------------------------------------------------------
+   1. Custom Properties (Design Tokens)
+   -------------------------------------------------------------------------- */
+
+:root {
+  /* -- Font Stacks -------------------------------------------------------- */
+  --font-sans: "Inter", ui-sans-serif, system-ui, -apple-system,
+    BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif;
+  --font-mono: "JetBrains Mono", ui-monospace, SFMono-Regular, "SF Mono",
+    Menlo, Consolas, "Liberation Mono", monospace;
+
+  /* -- Typography Scale (fluid clamp) ------------------------------------- */
+  --text-xs: clamp(0.7rem, 0.65rem + 0.25vw, 0.75rem);
+  --text-sm: clamp(0.8rem, 0.75rem + 0.25vw, 0.875rem);
+  --text-base: clamp(0.9rem, 0.85rem + 0.25vw, 1rem);
+  --text-lg: clamp(1.05rem, 0.95rem + 0.5vw, 1.125rem);
+  --text-xl: clamp(1.15rem, 1rem + 0.75vw, 1.25rem);
+  --text-2xl: clamp(1.4rem, 1.15rem + 1.25vw, 1.5rem);
+  --text-3xl: clamp(1.7rem, 1.3rem + 2vw, 1.875rem);
+  --text-4xl: clamp(2rem, 1.5rem + 2.5vw, 2.25rem);
+  --text-5xl: clamp(2.5rem, 1.75rem + 3.75vw, 3rem);
+  --text-6xl: clamp(3rem, 2rem + 5vw, 3.75rem);
+  --text-7xl: clamp(3.5rem, 2.25rem + 6.25vw, 4.5rem);
+
+  /* -- Spacing Scale ------------------------------------------------------- */
+  --space-xs: 0.25rem;
+  --space-sm: 0.5rem;
+  --space-md: 1rem;
+  --space-lg: 1.5rem;
+  --space-xl: 2rem;
+  --space-2xl: 3rem;
+  --space-3xl: 4rem;
+  --space-4xl: 6rem;
+  --space-5xl: 8rem;
+
+  /* -- Elevation Shadows (green glow) ------------------------------------- */
+  --elevation-1: 0 1px 3px rgba(0, 0, 0, 0.3), 0 1px 2px rgba(0, 0, 0, 0.24);
+  --elevation-2: 0 4px 16px rgba(34, 197, 94, 0.08),
+    0 1px 4px rgba(0, 0, 0, 0.2);
+  --elevation-3: 0 8px 30px rgba(34, 197, 94, 0.12),
+    0 2px 8px rgba(0, 0, 0, 0.2);
+  --elevation-4: 0 16px 48px rgba(34, 197, 94, 0.16),
+    0 4px 16px rgba(0, 0, 0, 0.2);
+
+  /* -- Easing Functions ---------------------------------------------------- */
+  --ease-out-expo: cubic-bezier(0.16, 1, 0.3, 1);
+  --ease-out-quart: cubic-bezier(0.25, 1, 0.5, 1);
+  --ease-in-out-quart: cubic-bezier(0.76, 0, 0.24, 1);
+  --ease-spring: cubic-bezier(0.34, 1.56, 0.64, 1);
+
+  /* -- Border Radius Scale ------------------------------------------------- */
+  --radius-sm: 0.25rem;
+  --radius-md: 0.5rem;
+  --radius-lg: 0.75rem;
+  --radius-xl: 1rem;
+  --radius-2xl: 1.5rem;
+  --radius-full: 9999px;
+
+  /* -- Brand Gradients ----------------------------------------------------- */
+  --gradient-brand: linear-gradient(135deg, #22c55e 0%, #a3e635 50%, #34d399 100%);
+  --gradient-brand-subtle: linear-gradient(
+    135deg,
+    rgba(34, 197, 94, 0.15) 0%,
+    rgba(163, 230, 53, 0.1) 50%,
+    rgba(52, 211, 153, 0.15) 100%
+  );
+  --gradient-hero: linear-gradient(135deg, #22c55e 0%, #a3e635 50%, #34d399 100%);
+  --gradient-hero-bg: radial-gradient(
+    ellipse at 50% 0%,
+    rgba(34, 197, 94, 0.12) 0%,
+    rgba(163, 230, 53, 0.06) 40%,
+    transparent 70%
+  );
+
+  /* -- Glass Effects ------------------------------------------------------- */
+  --glass-bg: rgba(2, 10, 2, 0.6);
+  --glass-border: rgba(34, 197, 94, 0.1);
+  --glass-blur: 12px;
+
+  /* -- Z-Index Scale ------------------------------------------------------- */
+  --z-dropdown: 100;
+  --z-sticky: 200;
+  --z-fixed: 300;
+  --z-modal-backdrop: 400;
+  --z-modal: 500;
+  --z-popover: 600;
+  --z-tooltip: 700;
+  --z-skip-link: 800;
+  --z-toast: 900;
+}
+
+/* --------------------------------------------------------------------------
+   2. Base Resets & Global Styles
+   -------------------------------------------------------------------------- */
+
+/* Smooth scrolling with reduced-motion respect */
+html {
+  scroll-behavior: smooth;
+}
+
+@media (prefers-reduced-motion: reduce) {
+  html {
+    scroll-behavior: auto;
+  }
+
+  *,
+  *::before,
+  *::after {
+    animation-duration: 0.01ms !important;
+    animation-iteration-count: 1 !important;
+    transition-duration: 0.01ms !important;
+    scroll-behavior: auto !important;
+  }
+}
+
+/* Selection color */
+::selection {
+  background: rgba(34, 197, 94, 0.2);
+  color: #f1f5f9;
+}
+
+::-moz-selection {
+  background: rgba(34, 197, 94, 0.2);
+  color: #f1f5f9;
+}
+
+/* Body */
+body {
+  background-color: #020a02;
+  color: #f1f5f9;
+  font-family: var(--font-sans);
+  font-size: var(--text-base);
+  line-height: 1.7;
+  -webkit-font-smoothing: antialiased;
+  -moz-osx-font-smoothing: grayscale;
+  text-rendering: optimizeLegibility;
+  overflow-x: hidden;
+}
+
+/* --------------------------------------------------------------------------
+   3. Scrollbar Styling
+   -------------------------------------------------------------------------- */
+
+/* Webkit / Blink */
+::-webkit-scrollbar {
+  width: 8px;
+  height: 8px;
+}
+
+::-webkit-scrollbar-track {
+  background: transparent;
+}
+
+::-webkit-scrollbar-thumb {
+  background: rgba(34, 197, 94, 0.3);
+  border-radius: var(--radius-full);
+}
+
+::-webkit-scrollbar-thumb:hover {
+  background: rgba(34, 197, 94, 0.5);
+}
+
+/* Firefox */
+* {
+  scrollbar-width: thin;
+  scrollbar-color: rgba(34, 197, 94, 0.3) transparent;
+}
+
+/* --------------------------------------------------------------------------
+   4. Utility Classes
+   -------------------------------------------------------------------------- */
+
+/* Green gradient text */
+.text-gradient-franken {
+  background: linear-gradient(135deg, #4ade80 0%, #bef264 50%, #34d399 100%);
+  -webkit-background-clip: text;
+  background-clip: text;
+  -webkit-text-fill-color: transparent;
+}
+
+/* Green glow */
+.glow-green {
+  box-shadow: 0 0 20px rgba(34, 197, 94, 0.3),
+    0 0 60px rgba(34, 197, 94, 0.1),
+    0 0 100px rgba(34, 197, 94, 0.05);
+}
+
+/* Hero section gradient background */
+.bg-gradient-franken-hero {
+  background: var(--gradient-hero-bg);
+  position: relative;
+}
+
+.bg-gradient-franken-hero::before {
+  content: "";
+  position: absolute;
+  inset: 0;
+  background: radial-gradient(
+    circle at 30% 20%,
+    rgba(34, 197, 94, 0.08) 0%,
+    transparent 50%
+  ),
+  radial-gradient(
+    circle at 70% 60%,
+    rgba(163, 230, 53, 0.05) 0%,
+    transparent 50%
+  );
+  pointer-events: none;
+}
+
+/* Glass morphism card */
+.glass-card {
+  background: var(--glass-bg);
+  backdrop-filter: blur(var(--glass-blur));
+  -webkit-backdrop-filter: blur(var(--glass-blur));
+  border: 1px solid var(--glass-border);
+  border-radius: var(--radius-xl);
+  box-shadow: var(--elevation-2);
+}
+
+/* --------------------------------------------------------------------------
+   5. Accessibility - Skip Link
+   -------------------------------------------------------------------------- */
+
+.skip-link {
+  position: absolute;
+  top: -100%;
+  left: var(--space-md);
+  z-index: var(--z-skip-link);
+  padding: var(--space-sm) var(--space-md);
+  background: #22c55e;
+  color: #020a02;
+  font-weight: 600;
+  font-size: var(--text-sm);
+  border-radius: 0 0 var(--radius-md) var(--radius-md);
+  text-decoration: none;
+  transition: top 0.2s var(--ease-out-expo);
+}
+
+.skip-link:focus {
+  top: 0;
+  outline: 2px solid #a3e635;
+  outline-offset: 2px;
+}
+
+/* --------------------------------------------------------------------------
+   6. Focus Styles
+   -------------------------------------------------------------------------- */
+
+:focus-visible {
+  outline: 2px solid rgba(34, 197, 94, 0.6);
+  outline-offset: 2px;
+}

