+import { useEffect, useRef } from "react";
+
+export default function GlowOrbits() {
+  const rootRef = useRef<HTMLDivElement>(null);
+
+  useEffect(() => {
+    if (!rootRef.current) return;
+
+    const mediaQuery = window.matchMedia("(prefers-reduced-motion: reduce)");
