+              <p className="mt-4 text-center text-sm font-medium text-slate-300">
+                {screenshots[resolvedLightboxIndex].title}
+                <span className="ml-2 text-slate-500">
+                  {resolvedLightboxIndex + 1} / {screenshots.length}
+                </span>
+              </p>
+            </motion.div>
+          </motion.div>
+        )}
+      </AnimatePresence>
+    </>
+  );
